head.script:
//==================================================================================================================
// id       : fi_201_01_11b
// 이름     : BIDC 매출입전표 발행
// 경로     : 자회사 / 회계/재무회계/일반회계/전표관리/
// 작 성 자 : 오영재
// 작 업 일 : 2025-12-09
// 사용계정 : 내부
// 비고     :
//
// 업로드   :
// 다운로드 : 
// 레포트   :
// 호출     : 
//==================================================================================================================

// 전역 변수
scwin.memJson = $c.data.getMemInfo();

scwin.vLoginCoCd = $c.gus.cfIsNull(scwin.memJson.coCd) ? '' : scwin.memJson.coCd;
scwin.vLoginCoClsCd = $c.gus.cfIsNull(scwin.memJson.coClsCd) ? '' : scwin.memJson.coClsCd;
scwin.vAcctDeptCd = scwin.memJson.acctDeptCd;

scwin.vEmpNo = scwin.memJson.empNo;
scwin.vEmpNm = scwin.memJson.userNm;

scwin.strCurDate = $c.date.getServerDateTime("yyyyMMdd");	

scwin.onpageload = function() {

};

scwin.onUdcCompleted = function() {

	const codeOptions = [
        { grpCd : "ZZ021", compID : "gr_prov:apprvStsCd"},
        { grpCd : "RC423", compID : "gr_prov:delYn"}
    ];

    $c.data.setCommonCode(codeOptions, scwin.onCommonCodeLoadCallbackFunc);
};


scwin.onCommonCodeLoadCallbackFunc = function() {
	//공통코드 조회 후에 초기화 실행.

    lc_slipKndCd.setSelectedIndex(0);
	lc_bidcDelYn.setSelectedIndex(0);

	ed_drawEmpNo.setValue( scwin.vEmpNo );
	ed_drawEmpNm.setValue( scwin.vEmpNm );

    //디폴트 날짜 변경(1월1일 ~ 해당월말일까지)	
	ed_slipDateFrom.setValue( scwin.strCurDate.substring(0, 6) + "01" );
	ed_slipDateTo.setValue( scwin.strCurDate) ; 

	// 작성자 udc_ComCode OnKeyup 이벤트 바인딩
	ed_drawEmpNo.bind("onkeyup", scwin.udc_drawEmpNo_onkeyup);

    //디버깅용
    // ed_slipDateFrom.setValue("20250301");
    // ed_slipDateTo.setValue("20250331");
    // lc_bidcDelYn.setSelectedIndex(0);

	scwin.f_Retrieve();
};


//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {  
	let ret;
    ret = $c.gus.cfValidate([ ed_slipDateFrom,ed_slipDateTo,lc_slipKndCd ]); 
    if (!ret)
		return true;

	if(ed_slipDateFrom.getValue() == "" || ed_slipDateTo.getValue() == ""){
		await $c.win.alert("전표일자는 필수 입력 항목입니다.");
		ed_slipDateFrom.focus();
		return;
	}

	// AS-IS : f_BetweenCheck 으로 구현 - 일자 유효성 체크라 cfIsAfterDate와 기능이 동일
	// if (!scwin.f_BetweenCheck(ed_slipDateFrom.getValue(), ed_slipDateTo.getValue())) { 
	if (!$c.gus.cfIsAfterDate(ed_slipDateFrom.getValue(), ed_slipDateTo.getValue())) {
		await $c.win.alert($c.data.getMessage(MSG_CM_ERR_057, "전표일자To", "전표일자From")); // %1은(는) %2 보다 큰 값으로 입력하십시오.
        ed_drawAcctDeptCd.focus();
        return;
    }

	// AS-IS 에서 일자 유효성 체크가 중복되어있으나 해당 부분 우선 유지
	if (!$c.gus.cfIsAfterDate(ed_slipDateFrom.getValue().trim(), ed_slipDateTo.getValue().trim())) {
		await $c.win.alert($c.data.getMessage(MSG_CM_ERR_039)); // 시작일자가 종료일자 이전이어야 합니다.
	 	ed_slipDateFrom.focus();
	    return;
	}  

	ed_slipDateFrom.setValue( ed_slipDateFrom.getValue().trim() );
	ed_slipDateTo.setValue( ed_slipDateTo.getValue().trim() );

	dma_search.set("empNo", scwin.vEmpNo);
    dma_search.set("acctDeptCd", scwin.vAcctDeptCd);

    $c.sbm.execute(sbm_search);
};

//-------------------------------------------------------------------------
// 삭제
//-------------------------------------------------------------------------
scwin.f_Delete = async function() {

	if (lc_bidcDelYn.getSelectedIndex() == 1) {
		await $c.win.alert("BIDC전표 삭제된 내역입니다.");
		return;
	}

	if(ds_bidcSlip.getModifiedIndex().length < 1){
	    await $c.win.alert($c.data.getMessage(MSG_CM_ERR_056, "데이타"));
	    return;
	}

   // 이미 발행된건 삭제하지 않는다.
	for (i=0; i< ds_bidcSlip.getRowCount() ; i++){
		if(ds_bidcSlip.getRowStatus(i) == "U" && ds_bidcSlip.getCellData(i,"slipNo") != "" ){
			await $c.win.alert(i+"번째 데이타는 전표내역이 있어 삭제할 수 없습니다.");
			return;
		} 
	}

    //삭제할 것만 추려서 넣는다.
    let data = ds_bidcSlip.getModifiedJSON();
    ds_targetBidcSlip.setJSON(data);
    ds_targetBidcSlip.modifyAllStatus("U");

    let ret = await $c.win.confirm($c.data.getMessage(MSG_CM_CRM_008, "선택하신 데이타"));
	if(ret==true){	
        $c.sbm.execute(sbm_delete);
	}
};

scwin.f_Save = async function() {
	if (lc_bidcDelYn.getSelectedIndex() == 1) {
		await $c.win.alert("BIDC전표 삭제된 내역입니다. 발행 할 수 없습니다.");
		return;
	}

	if(ds_bidcSlip.getModifiedIndex().length < 1){
	    await $c.win.alert($c.data.getMessage(MSG_CM_ERR_056, "데이타"));
	    return;
	}

	var i             = 0;
  	var count         = 0;
  	var slipCount     = 0;

	// 조회결과 데이터셋의 루프만큼
	for ( i = 0 ; i < ds_bidcSlip.getRowCount() ; i++) {
	    // 체크된 것만 로직을 타고, 
		if ( ds_bidcSlip.getCellData(i,"checkYn") == "T") {
			count = count + 1;	        
	        // 행의 전표번호가 없다면 전표번호의 갯수를 1증가한다. 
	        if ( ds_bidcSlip.getCellData(i,"slipNo") != "") {
	        	slipCount = slipCount + 1;
	        }	        
	    }
	}

	if ( count > 1) {
		await $c.win.alert("전표 발행은 1건씩 가능합니다.");
		return false;
	}

	//var valueObject = new Object();
    let data;

	// 조회결과 데이터셋의 루프만큼
	for ( i = 0 ; i < ds_bidcSlip.getRowCount(); i++) {
		// 체크된 것만 로직을 타고, 
        if ( ds_bidcSlip.getCellData(i,"checkYn") == "T") {
            data = {
                "bidcSlipNo" : ds_bidcSlip.getCellData(i,"bidcSlipNo"), 
                "slipKndCd" : ds_bidcSlip.getCellData(i,"slipKndCd"), 
                "slipAcctDeptCd" : ds_bidcSlip.getCellData(i,"slipAcctDeptCd")
            }
		}
	}

	//var sFeatures =	"dialogWidth:840px; dialogHeight:800px; scroll:yes; resizable:yes; status:yes;";
    //debugger;
    //console.log( data );
	sURL = "/ui/ac/fi/gnrlaccount/slipmgnt/fi_201_01_11p.xml";
    const options = {
        id: "fi_201_01_11p",
        type: "browserPopup",
        modal : true,
        popupName:"BIDC 매출입전표발행",
        width: 1080,
        height:950
    };

    let rtrValue = await $c.win.openPopup(sURL,options,data);

	if (rtrValue != null) {
		if(rtrValue.SlipNo == "Y"){
			scwin.f_Retrieve();
		}
	}

};

//-------------------------------------------------------------------------
// 숫자차이체크
//  - AS-IS에서 일자 유효성 체크로 사용하나, cfIsAfterDate로 대체 가능한 함수
//-------------------------------------------------------------------------
scwin.f_BetweenCheck = function(str1,str2){
  	if((str1==""&& str2!="" ) || (str1!=""&&str2 =="")) {
  		return false;
  	}
  	if(parseInt(str2)-parseInt(str1) < 0) {
  		return false;
	}
	return true;
};

scwin.formatSlipKnd = function(v) {
    return (v == "K12") ? "매출전표" : "매입전표";
};

//-------------------------------------------------------------------------
//팝업
//-------------------------------------------------------------------------
scwin.f_openPopUp = function(flag, check) {
	let param;
    let resignYn;

    switch (flag) {
        case '1':  // 부서조회
			// @TODO 아래 param 부분 확인이 필요
            param = "," + scwin.vLoginCoCd + "," + scwin.vLoginCoClsCd +",0";  

			// Select ID : retrieveAcctDeptCdInfo6
			udc_drawAcctDeptCd.cfCommonPopUp(
				scwin.udc_drawAcctDeptCd_callbackfunc // 팝업 콜백 리턴결과 Array 형태로 SQL Select 순서로 Return
				,ed_drawAcctDeptCd.getValue().trim()                  // 화면에서의 ??? Code Element의 Value
				,ed_drawAcctDeptNm.getValue()                  // 화면에서의 ??? Name Element의 Value
				,check                 // 결과가 1건 일때 원도우를 AutoClose 여부 (T:Close,F:Opened)
				,null					// 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) 	MAX:10     null(2)   "5"
				,null					// Title명's                         	null    "100,200"
				,null					// 보여주는 각 컬럼들의 폭               null    "100,200"
				,null					// 컬럼중에서 숨기는 컬럼 지정           null    "7,8,9,10"		
				,param					// SQL절의 WHERE절에 원하는 조건을 선택함 MAX:12개까지 가능     null    "SHIP"
				,null					// POP-UP 띄울때 원도우의 사용자 정의 폭              null    "500"
				,null					// POP-UP 띄울때 윈도우의 사용자 정의 높이             null    "600"
				,null					// 윈도우 위치 Y좌표
				,null					// 윈도우 위치 X좌표  
				,null					// 중복체크여부
				,null 					// 전체검색허용여부 ("F")
				,null					// POP-UP Window Title 검색어1,2(각화면에서 변경할경우)        null    "Win타이틀,검색어1,검색어2"
				,null					// Data건수가 0건일때 Window를 띄우지 않음 리턴
		);

        break;

        case '2': // 사원(작성자)
            param=''; 
            resignYn ='';

			var chkValue = chk_resignYn.getValue();
			resignYn = (chkValue != null && chkValue.length > 0) ? 'Y' : '' ;
            param = scwin.vLoginCoCd + "," + scwin.vLoginCoClsCd + "," + resignYn;

			// Select ID : retrieveAcEmpInfo
            udc_drawEmpNo.cfCommonPopUp(
				scwin.udc_drawEmpNo_callbackfunc
				, ed_drawEmpNo.getValue().trim()
				, ed_drawEmpNm.getValue()
				, check, null, null, null, null
				,param, null, null, null, null); 
        	break;

        default:
        break; 
    }
};

///////////////////////////////////////////// S U B M I S S I O N    E V E N T /////////////////////////////////////////

// 조회
scwin.sbm_search_submitdone = async function(e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) 
		return;

    let count = ds_bidcSlip.getRowCount();
    if(count == 0 ) 
		await $c.win.alert($c.data.getMessage(MSG_CM_WRN_002)); // 조회결과가 존재하지 않습니다.

	ed_totalRows.setValue(ds_bidcSlip.getRowCount());
};

scwin.sbm_delete_submitdone = function(e) {
	if(e.responseJSON.resultDataSet[0].Code == 0) {
		$c.win.alert(MSG_CM_INF_004);
		scwin.f_Retrieve();
	}
};


///////////////////////////////////////////// U D C   E V E N T /////////////////////////////////////////

// 작성부서 onClick
scwin.udc_drawAcctDeptCd_onclickEvent = function (e) {
    scwin.f_openPopUp('1','F');
};
scwin.udc_drawAcctDeptCd_onblurCodeEvent = function (e) {
    scwin.f_openPopUp('1','T');
};

// 작성부서 팝업 콜백함수
scwin.udc_drawAcctDeptCd_callbackfunc = function(rtnList) {
	$c.gus.cfSetReturnValue(rtnList, ed_drawAcctDeptCd, ed_drawAcctDeptNm);
};

// 작성자 onClick
scwin.udc_drawEmpNo_onclickEvent = function (e) {
    scwin.f_openPopUp('2','F');
};
scwin.udc_drawEmpNo_onblurCodeEvent = function (e) {
    scwin.f_openPopUp('2','T');
};

// 작성자 팝업 콜백함수
scwin.udc_drawEmpNo_callbackfunc = function(rtnList) {
	$c.gus.cfSetReturnValue(rtnList, ed_drawEmpNo, ed_drawEmpNm);
};

// 작성자 코드 onKeyup - 영문/숫자만 입력 허용, 첫글자는 영문/숫자, 이후는 숫자만 허용
scwin.udc_drawEmpNo_onkeyup = function(e) {
	let val = ed_drawEmpNo.getValue();

	let first = val.charAt(0);
	let rest = val.substring(1);

	// 첫글자: 영문/숫자 아니면 제거
	if (!/^[A-Z0-9]/.test(first)) {
		first = '';
	}

	// 이후: 숫자만
	rest = rest.replace(/[^0-9]/g, '');

	let filtered = first + rest;

	if (val !== filtered) {
		ed_drawEmpNo.setValue(filtered);
	}
};

///////////////////////////////////////////// C O M P O N E N T   E V E N T /////////////////////////////////////////


scwin.gr_gridView1_oncellclick = async function (rowIndex, columnIndex, columnId) {
    if(columnId=="slipNo" && rowIndex >=0 && ds_bidcSlip.getCellData(rowIndex,"slipNo") != ""){
		$c.gus.cfShowSlipInfo(ds_bidcSlip.getCellData(rowIndex,"slipNo"));	
	}

    if ( columnId == "checkYn"){
    	if (ds_bidcSlip.getCellData(rowIndex,"slipNo") != ""){
    		await $c.win.alert("전표가 이미 발행 된 상태입니다.")	;
    		ds_bidcSlip.setCellData(rowIndex,"checkYn", "F");
    	}
    }
};

scwin.btn_delete_onclick = function (e) {
    scwin.f_Delete();
};

scwin.bSav1_onclick = function (e) {
    scwin.f_Save();
};

scwin.btn_retrieve_onclick = function (e) {
    scwin.f_Retrieve();
};

// BL번호 대문자
scwin.ed_blNo_onkeyup = function (e) {
	this.setValue(e.target.value.toUpperCase());
};

// BIDC전표 대문자
scwin.ed_bidcSlipNo_onkeyup = function (e) {
	this.setValue(e.target.value.toUpperCase());
};
